   261 |     }
   262 |     E = R2;
   263 |   } else {
   264 |     auto *RHSCMP = dyn_cast<ICmpInst>(RHS);
   265 |     if (!RHSCMP)
   266 |       return std::nullopt;
   267 |     // Don't allow pointers. Splat vectors are fine.
   268 |     if (!RHSCMP->getOperand(0)->getType()->isIntOrIntVectorTy())
