   270 | 
   271 |     PredR = RHSCMP->getPredicate();
   272 | 
   273 |     Value *R1 = RHSCMP->getOperand(0);
   274 |     R2 = RHSCMP->getOperand(1);
   275 |     bool Ok = false;
   276 |     if (!match(R1, m_And(m_Value(R11), m_Value(R12)))) {
   277 |       // As before, model no mask as a trivial mask if it'll let us do an
